  1→//! Configuration validation engine.
  2→//!
  3→//! Validates TOML configuration files against the known schema, detects
  4→//! unknown/misspelled fields, and reports security warnings.
  5→
  6→use std::path::Path;
  7→
  8→use crate::schema::MoltisConfig;
  9→
 10→#[path = "validate/schema_map.rs"]
 11→mod schema_map;
 12→#[path = "validate/semantic.rs"]
 13→mod semantic;
 14→
 15→/// Severity level for a diagnostic.
 16→#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
 17→pub enum Severity {
 18→    Error,
 19→    Warning,
 20→    Info,
 21→}
 22→
 23→impl std::fmt::Display for Severity {
 24→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 25→        match self {
 26→            Self::Error => write!(f, "error"),
 27→            Self::Warning => write!(f, "warning"),
 28→            Self::Info => write!(f, "info"),
 29→        }
 30→    }
 31→}
 32→
 33→/// A single validation diagnostic.
 34→#[derive(Debug, Clone)]
 35→pub struct Diagnostic {
 36→    pub severity: Severity,
 37→    /// Category: "syntax", "unknown-field", "deprecated-field", "unknown-provider", "type-error",
 38→    /// "security", "file-ref"
 39→    pub category: &'static str,
 40→    /// Dotted path, e.g. "server.bnd"
 41→    pub path: String,
 42→    pub message: String,
 43→}
 44→
 45→/// Result of validating a configuration file.
 46→#[derive(Debug, Clone)]
 47→pub struct ValidationResult {
 48→    pub diagnostics: Vec<Diagnostic>,
 49→    pub config_path: Option<std::path::PathBuf>,
 50→}
 51→
 52→impl ValidationResult {
 53→    /// Returns `true` if any diagnostic is an error.
 54→    #[must_use]
 55→    pub fn has_errors(&self) -> bool {
 56→        self.diagnostics
 57→            .iter()
 58→            .any(|d| d.severity == Severity::Error)
 59→    }
 60→
 61→    /// Count diagnostics by severity.
 62→    #[must_use]
 63→    pub fn count(&self, severity: Severity) -> usize {
 64→        self.diagnostics
 65→            .iter()
 66→            .filter(|d| d.severity == severity)
 67→            .count()
 68→    }
 69→}
 70→
 71→pub fn validate(path: Option<&Path>) -> ValidationResult {
 72→    let config_path = if let Some(p) = path {
 73→        Some(p.to_path_buf())
 74→    } else {
 75→        crate::loader::find_config_file()
 76→    };
 77→
 78→    let Some(ref actual_path) = config_path else {
 79→        return ValidationResult {
 80→            diagnostics: vec![Diagnostic {
 81→                severity: Severity::Info,
 82→                category: "file-ref",
 83→                path: String::new(),
 84→                message: "no config file found; using defaults".into(),
 85→            }],
 86→            config_path: None,
 87→        };
 88→    };
 89→
 90→    match std::fs::read_to_string(actual_path) {
 91→        Ok(content) => {
 92→            let mut result = validate_toml_str(&content);
 93→            result.config_path = Some(actual_path.clone());
 94→            semantic::check_file_references(&content, actual_path, &mut result.diagnostics);
 95→            result
 96→        },
 97→        Err(e) => ValidationResult {
 98→            diagnostics: vec![Diagnostic {
 99→                severity: Severity::Error,
100→                category: "syntax",
101→                path: String::new(),
102→                message: format!("failed to read config file: {e}"),
103→            }],
104→            config_path: Some(actual_path.clone()),
105→        },
106→    }
107→}
108→
109→/// Validate a TOML string without file-system side effects (useful for tests
110→/// and the gateway).
111→#[must_use]
112→pub fn validate_toml_str(toml_str: &str) -> ValidationResult {
113→    let mut diagnostics = Vec::new();
114→
115→    // 1. Syntax - parse raw TOML
116→    let toml_value: toml::Value = match toml::from_str(toml_str) {
117→        Ok(v) => v,
118→        Err(e) => {
119→            diagnostics.push(Diagnostic {
120→                severity: Severity::Error,
121→                category: "syntax",
122→                path: String::new(),
123→                message: format!("TOML syntax error: {e}"),
124→            });
125→            return ValidationResult {
126→                diagnostics,
127→                config_path: None,
128→            };
129→        },
130→    };
131→
132→    // 2. Unknown fields - walk the TOML tree against KnownKeys
133→    let schema = schema_map::build_schema_map();
134→    schema_map::check_unknown_fields(&toml_value, &schema, "", &mut diagnostics);
135→
136→    // 3. Deprecation warnings on raw TOML keys
137→    let conflicting_replacements = semantic::check_deprecated_fields(&toml_value, &mut diagnostics);
138→
139→    // 4. Provider name hints
140→    if let Some(providers) = toml_value.get("providers").and_then(|v| v.as_table()) {
141→        semantic::check_provider_names(providers, &mut diagnostics);
142→    }
143→
144→    // 5. Type check - attempt full deserialization
145→    if let Err(e) = toml::from_str::<MoltisConfig>(toml_str) {
146→        let message = format!("type error: {e}");
147→        if !semantic::should_suppress_deprecated_conflict_type_error(
148→            &message,
149→            &conflicting_replacements,
150→        ) {
151→            diagnostics.push(Diagnostic {
152→                severity: Severity::Error,
153→                category: "type-error",
154→                path: String::new(),
155→                message,
156→            });
157→        }
158→    }
159→
160→    // 6. Semantic warnings on parsed config (only if it parses)
161→    if let Ok(config) = toml::from_str::<MoltisConfig>(toml_str) {
162→        semantic::check_semantic_warnings(&config, &mut diagnostics);
163→    }
164→
165→    ValidationResult {
166→        diagnostics,
167→        config_path: None,
168→    }
169→}
