171→fn levenshtein(a: &str, b: &str) -> usize {
172→    let a_bytes = a.as_bytes();
173→    let b_bytes = b.as_bytes();
174→    let n = a_bytes.len();
175→    let m = b_bytes.len();
176→    if n == 0 {
177→        return m;
178→    }
179→    if m == 0 {
180→        return n;
181→    }
182→
183→    let mut prev: Vec<usize> = (0..=m).collect();
184→    let mut curr = vec![0; m + 1];
185→    for (i, &ac) in a_bytes.iter().enumerate() {
186→        curr[0] = i + 1;
187→        for (j, &bc) in b_bytes.iter().enumerate() {
188→            let cost = if ac == bc {
189→                0
190→            } else {
191→                1
192→            };
193→            let del = prev[j + 1] + 1;
194→            let ins = curr[j] + 1;
195→            let sub = prev[j] + cost;
196→            curr[j + 1] = del.min(ins).min(sub);
197→        }
198→        std::mem::swap(&mut prev, &mut curr);
199→    }
200→    prev[m]
201→}
202→
203→fn suggest<'a>(needle: &str, candidates: &[&'a str], max_distance: usize) -> Option<&'a str> {
204→    let mut best: Option<(&'a str, usize)> = None;
205→    for &candidate in candidates {
206→        let dist = levenshtein(needle, candidate);
207→        if dist <= max_distance {
208→            match best {
209→                Some((_, best_dist)) if dist < best_dist => best = Some((candidate, dist)),
210→                None => best = Some((candidate, dist)),
211→                _ => {},
212→            }
213→        }
214→    }
215→    best.map(|(candidate, _)| candidate)
216→}
