 41→/// Typed chat message for the LLM provider interface.
 42→///
 43→/// Only contains LLM-relevant fields — metadata like `created_at`, `model`,
 44→/// `provider`, `inputTokens`, `outputTokens` cannot exist here, so they
 45→/// can never leak into provider API requests.
 46→#[derive(Debug, Clone)]
 47→pub enum ChatMessage {
 48→    System {
 49→        content: String,
 50→    },
 51→    User {
 52→        content: UserContent,
 53→        /// Optional sender name for channel messages (Telegram, Discord, etc.).
 54→        name: Option<String>,
 55→    },
 56→    Assistant {
 57→        content: Option<String>,
 58→        tool_calls: Vec<ToolCall>,
 59→    },
 60→    Tool {
 61→        tool_call_id: String,
 62→        content: String,
 63→    },
 64→}
