 66→/// User message content: plain text or multimodal (text + images).
 67→#[derive(Debug, Clone)]
 68→pub enum UserContent {
 69→    Text(String),
 70→    Multimodal(Vec<ContentPart>),
 71→}
 72→
 73→impl UserContent {
 74→    /// Create a text-only user content.
 75→    pub fn text(s: impl Into<String>) -> Self {
 76→        Self::Text(s.into())
 77→    }
 78→}
 79→
 80→/// A single part of a multimodal content array.
 81→#[derive(Debug, Clone)]
 82→pub enum ContentPart {
 83→    Text(String),
 84→    Image { media_type: String, data: String },
 85→}
 86→
 87→impl ChatMessage {
 88→    /// Create a system message.
 89→    pub fn system(content: impl Into<String>) -> Self {
 90→        Self::System {
 91→            content: content.into(),
 92→        }
 93→    }
 94→
 95→    /// Create a user message with plain text.
 96→    pub fn user(content: impl Into<String>) -> Self {
 97→        Self::User {
 98→            content: UserContent::Text(content.into()),
 99→            name: None,
100→        }
101→    }
102→
103→    /// Create a user message with plain text and a sender name.
104→    pub fn user_named(content: impl Into<String>, name: impl Into<String>) -> Self {
105→        Self::User {
106→            content: UserContent::Text(content.into()),
107→            name: Some(name.into()),
108→        }
109→    }
110→
111→    /// Create a user message with multimodal content.
112→    pub fn user_multimodal(parts: Vec<ContentPart>) -> Self {
113→        Self::User {
114→            content: UserContent::Multimodal(parts),
115→            name: None,
116→        }
117→    }
118→
119→    /// Create a user message with multimodal content and a sender name.
120→    pub fn user_multimodal_named(parts: Vec<ContentPart>, name: impl Into<String>) -> Self {
121→        Self::User {
122→            content: UserContent::Multimodal(parts),
123→            name: Some(name.into()),
124→        }
125→    }
126→
127→    /// Create an assistant message with text only (no tool calls).
128→    pub fn assistant(content: impl Into<String>) -> Self {
129→        Self::Assistant {
130→            content: Some(content.into()),
131→            tool_calls: vec![],
132→        }
133→    }
134→
135→    /// Create an assistant message with tool calls (and optional text).
136→    pub fn assistant_with_tools(content: Option<String>, tool_calls: Vec<ToolCall>) -> Self {
137→        Self::Assistant {
138→            content,
139→            tool_calls,
140→        }
141→    }
142→
143→    /// Create a tool result message.
144→    pub fn tool(tool_call_id: impl Into<String>, content: impl Into<String>) -> Self {
145→        Self::Tool {
146→            tool_call_id: tool_call_id.into(),
147→            content: content.into(),
148→        }
149→    }
150→
151→    /// Convert to OpenAI-compatible JSON format.
152→    ///
153→    /// Used by providers that speak the OpenAI Chat Completions API:
154→    /// OpenAI, Mistral, Copilot, Kimi, Cerebras, etc.
155→    #[must_use]
156→    pub fn to_openai_value(&self) -> serde_json::Value {
157→        match self {
158→            ChatMessage::System { content } => {
159→                serde_json::json!({ "role": "system", "content": content })
160→            },
161→            ChatMessage::User { content, name } => {
162→                let mut msg = match content {
163→                    UserContent::Text(text) => {
164→                        serde_json::json!({ "role": "user", "content": text })
165→                    },
166→                    UserContent::Multimodal(parts) => {
167→                        let blocks: Vec<serde_json::Value> = parts
168→                            .iter()
169→                            .map(|part| match part {
170→                                ContentPart::Text(text) => {
171→                                    serde_json::json!({ "type": "text", "text": text })
172→                                },
173→                                ContentPart::Image { media_type, data } => {
174→                                    let data_uri = format!("data:{media_type};base64,{data}");
175→                                    serde_json::json!({
176→                                        "type": "image_url",
177→                                        "image_url": { "url": data_uri }
178→                                    })
179→                                },
180→                            })
181→                            .collect();
182→                        serde_json::json!({ "role": "user", "content": blocks })
183→                    },
184→                };
185→                if let Some(n) = name {
186→                    msg["name"] = serde_json::Value::String(n.clone());
187→                }
188→                msg
189→            },
190→            ChatMessage::Assistant {
191→                content,
192→                tool_calls,
193→            } => {
194→                if tool_calls.is_empty() {
195→                    serde_json::json!({
196→                        "role": "assistant",
197→                        "content": content.as_deref().unwrap_or(""),
198→                    })
199→                } else {
200→                    let tc_json: Vec<serde_json::Value> = tool_calls
201→                        .iter()
202→                        .map(|tc| {
203→                            let mut tc_val = serde_json::json!({
204→                                "id": tc.id,
205→                                "type": "function",
206→                                "function": {
207→                                    "name": tc.name,
208→                                    "arguments": tc.arguments.to_string(),
209→                                }
210→                            });
211→                            if let Some(ref meta) = tc.metadata
212→                                && let Some(obj) = tc_val.as_object_mut()
213→                            {
214→                                for (k, v) in meta {
215→                                    obj.insert(k.clone(), v.clone());
216→                                }
217→                            }
218→                            tc_val
219→                        })
220→                        .collect();
221→                    let mut msg = serde_json::json!({
222→                        "role": "assistant",
223→                        "tool_calls": tc_json,
224→                    });
225→                    if let Some(text) = content {
226→                        msg["content"] = serde_json::Value::String(text.clone());
227→                    }
228→                    msg
229→                }
230→            },
231→            ChatMessage::Tool {
232→                tool_call_id,
233→                content,
234→            } => {
235→                serde_json::json!({
236→                    "role": "tool",
237→                    "tool_call_id": tool_call_id,
238→                    "content": content,
239→                })
240→            },
241→        }
242→    }
243→}
244→
245→/// Extract allowlisted metadata keys from a tool-call JSON object.
246→///
247→/// Returns `None` when no metadata keys are present, keeping the common path
248→/// allocation-free.
249→#[must_use]
250→pub fn extract_tool_call_metadata(
251→    tc: &serde_json::Value,
252→) -> Option<serde_json::Map<String, serde_json::Value>> {
253→    let obj = tc.as_object()?;
254→    let meta: serde_json::Map<_, _> = TOOL_CALL_METADATA_KEYS
255→        .iter()
256→        .filter_map(|&k| obj.get(k).map(|v| (k.to_string(), v.clone())))
257→        .collect();
258→    if meta.is_empty() {
259→        None
260→    } else {
261→        Some(meta)
262→    }
263→}
