265→/// Convert persisted JSON messages (from session store) to typed `ChatMessage`s.
266→///
267→/// Skips messages that don't have a valid `role` field, logging a warning.
268→/// Metadata fields (`created_at`, `model`, `provider`, `inputTokens`,
269→/// `outputTokens`, `channel`) are silently dropped — they only exist in
270→/// the persisted JSON, not in `ChatMessage`.
271→pub fn values_to_chat_messages(values: &[serde_json::Value]) -> Vec<ChatMessage> {
272→    let mut messages = Vec::with_capacity(values.len());
273→    // Track tool_call IDs emitted by assistant messages so we only include
274→    // tool/tool_result messages that have a matching assistant tool_call.
275→    // Orphan tool results (e.g. from explicit /sh commands) would cause
276→    // provider API errors.
277→    let mut pending_tool_call_ids: std::collections::HashSet<String> =
278→        std::collections::HashSet::new();
279→    for (i, val) in values.iter().enumerate() {
280→        let Some(role) = val["role"].as_str() else {
281→            tracing::warn!(index = i, "skipping message with missing/invalid role");
282→            continue;
283→        };
284→        match role {
285→            "system" => {
286→                let content = val["content"].as_str().unwrap_or("").to_string();
287→                messages.push(ChatMessage::system(content));
288→            },
289→            "user" => {
290→                // Extract sender name from persisted channel metadata.
291→                let sender_name = val
292→                    .get("channel")
293→                    .and_then(|ch| {
294→                        ch["sender_name"]
295→                            .as_str()
296→                            .or_else(|| ch["username"].as_str())
297→                    })
298→                    .map(|s| s.to_string());
299→
300→                let document_context = val["documents"].as_array().and_then(|documents| {

300→                let document_context = val["documents"].as_array().and_then(|documents| {
301→                    let mut sections = Vec::new();
302→                    for document in documents {
303→                        let Some(display_name) = document["display_name"].as_str() else {
304→                            continue;
305→                        };
306→                        let Some(mime_type) = document["mime_type"].as_str() else {
307→                            continue;
308→                        };
309→                        let Some(media_ref) = document["media_ref"].as_str() else {
310→                            continue;
311→                        };
312→                        let absolute_path = document_absolute_path_from_media_ref(media_ref);
313→                        sections.push(format!(
314→                            "filename: {display_name}\nmime_type: {mime_type}\nlocal_path: {absolute_path}\nmedia_ref: {media_ref}"
315→                        ));
316→                    }
317→                    if sections.is_empty() {
318→                        None
319→                    } else {
320→                        let mut rendered = vec!["[Inbound documents available]".to_string()];
321→                        rendered.extend(sections);
322→                        Some(rendered.join("\n\n"))
323→                    }
324→                });
325→
326→                // Content can be a string or an array (multimodal).
327→                if let Some(text) = val["content"].as_str() {
328→                    let content = if let Some(ref document_context) = document_context {
329→                        if text.trim().is_empty() {
330→                            document_context.clone()
331→                        } else {
332→                            format!("{text}\n\n{document_context}")
333→                        }
334→                    } else {
335→                        text.to_string()
336→                    };
337→                    messages.push(ChatMessage::User {
338→                        content: UserContent::Text(content),
339→                        name: sender_name,
340→                    });
341→                } else if let Some(arr) = val["content"].as_array() {
342→                    let mut parts: Vec<ContentPart> = arr
343→                        .iter()
344→                        .filter_map(|block| {
345→                            let block_type = block["type"].as_str()?;
346→                            match block_type {
347→                                "text" => {
348→                                    let text = block["text"].as_str()?.to_string();
349→                                    Some(ContentPart::Text(text))
350→                                },
351→                                "image_url" => {
352→                                    let url = block["image_url"]["url"].as_str()?;
353→                                    let (media_type, data) = parse_data_uri(url)?;
354→                                    Some(ContentPart::Image {
355→                                        media_type: media_type.to_string(),
356→                                        data: data.to_string(),
357→                                    })
358→                                },
359→                                _ => None,
360→                            }
361→                        })
362→                        .collect();
363→                    if let Some(document_context) = document_context {
364→                        if let Some(ContentPart::Text(text)) = parts
365→                            .iter_mut()
366→                            .find(|part| matches!(part, ContentPart::Text(_)))
367→                        {
368→                            if !text.trim().is_empty() {
369→                                text.push_str("\n\n");
370→                            }
371→                            text.push_str(&document_context);
372→                        } else {
373→                            parts.insert(0, ContentPart::Text(document_context));
374→                        }
375→                    }
376→                    messages.push(ChatMessage::User {
377→                        content: UserContent::Multimodal(parts),
378→                        name: sender_name,
379→                    });
380→                } else {
381→                    messages.push(ChatMessage::User {
382→                        content: UserContent::Text(document_context.unwrap_or_default()),
383→                        name: sender_name,
384→                    });
385→                }
386→            },
387→            "assistant" => {
388→                let content = val["content"].as_str().map(|s| s.to_string());
389→                let tool_calls: Vec<ToolCall> = val["tool_calls"]
390→                    .as_array()
391→                    .map(|tcs| {
392→                        tcs.iter()
393→                            .filter_map(|tc| {
394→                                let id = tc["id"].as_str()?.to_string();
395→                                let name = tc["function"]["name"].as_str()?.to_string();
396→                                let arguments =
397→                                    decode_tool_call_arguments(tc["function"].get("arguments"));
398→                                let metadata = extract_tool_call_metadata(tc);
399→                                Some(ToolCall {
400→                                    id,
401→                                    name,
402→                                    arguments,
403→                                    metadata,
404→                                })
405→                            })
406→                            .collect()
407→                    })
408→                    .unwrap_or_default();
409→                for tc in &tool_calls {
410→                    pending_tool_call_ids.insert(tc.id.clone());
411→                }
412→                messages.push(ChatMessage::Assistant {
413→                    content,
414→                    tool_calls,
415→                });
416→            },
417→            "tool" => {
418→                let tool_call_id = val["tool_call_id"].as_str().unwrap_or("").to_string();
419→                if !pending_tool_call_ids.remove(&tool_call_id) {
420→                    tracing::debug!(tool_call_id, "skipping orphan tool message");
421→                    continue;
422→                }
423→                let content = if let Some(s) = val["content"].as_str() {
424→                    s.to_string()
425→                } else {
426→                    val["content"].to_string()
427→                };
428→                messages.push(ChatMessage::tool(tool_call_id, content));
429→            },
430→            // tool_result entries are persisted tool execution output; convert
431→            // them to standard tool messages so the LLM sees its own results.
432→            "tool_result" => {
433→                let tool_call_id = val["tool_call_id"].as_str().unwrap_or("").to_string();
434→                if !pending_tool_call_ids.remove(&tool_call_id) {
435→                    tracing::debug!(tool_call_id, "skipping orphan tool_result message");
436→                    continue;
437→                }
438→                let content = if let Some(err) = val["error"].as_str() {
439→                    format!("Error: {err}")
440→                } else if let Some(result) = val.get("result") {
441→                    if let Some(s) = result.as_str() {
442→                        s.to_string()
443→                    } else {
444→                        result.to_string()
445→                    }
446→                } else {
447→                    String::new()
448→                };
449→                messages.push(ChatMessage::tool(tool_call_id, content));
450→            },
451→            // notice entries are UI-only informational messages.
452→            "notice" => continue,
453→            other => {
454→                tracing::warn!(
455→                    index = i,
456→                    role = other,
457→                    "skipping message with unknown role"
458→                );
459→            },
460→        }
461→    }
462→    messages
463→}
