466→
467→/// Events emitted during streaming LLM completion.
468→#[derive(Debug, Clone)]
469→pub enum StreamEvent {
470→    /// Text content delta.
471→    Delta(String),
472→    /// Raw provider event payload (for debugging API responses).
473→    ProviderRaw(serde_json::Value),
474→    /// Reasoning/planning text delta (not user-visible final answer text).
475→    ReasoningDelta(String),
476→    /// A tool call has started (content_block_start with tool_use).
477→    ToolCallStart {
478→        /// Tool call ID from the provider.
479→        id: String,
480→        /// Tool name being called.
481→        name: String,
482→        /// Index of this tool call in the response (0-based).
483→        index: usize,
484→        /// Provider-specific metadata (e.g. Gemini `thought_signature`).
485→        metadata: Option<serde_json::Map<String, serde_json::Value>>,
486→    },
487→    /// Streaming delta for tool call arguments (JSON fragment).
488→    ToolCallArgumentsDelta {
489→        /// Index of the tool call this delta belongs to.
490→        index: usize,
491→        /// JSON fragment to append to the arguments.
492→        delta: String,
493→    },
494→    /// A tool call's arguments are complete.
495→    ToolCallComplete {
496→        /// Index of the completed tool call.
497→        index: usize,
498→    },
499→    /// Stream completed successfully.
500→    Done(Usage),
501→    /// An error occurred.
502→    Error(String),
503→}
504→
505→/// LLM provider trait (Anthropic, OpenAI, Google, etc.).
506→#[async_trait]
507→pub trait LlmProvider: Send + Sync {
508→    fn name(&self) -> &str;
509→
510→    /// Model identifier (e.g. "claude-sonnet-4-20250514", "gpt-4o").
511→    fn id(&self) -> &str;
512→
513→    async fn complete(
514→        &self,
515→        messages: &[ChatMessage],
516→        tools: &[serde_json::Value],
517→    ) -> anyhow::Result<CompletionResponse>;
518→
519→    /// Whether this provider supports tool/function calling.
520→    /// Defaults to false; providers that handle the `tools` parameter
521→    /// in `complete()` should override this to return true.
522→    fn supports_tools(&self) -> bool {
523→        false
524→    }
525→
526→    /// Context window size in tokens for this model.
527→    /// Used to detect when conversation approaches the limit and trigger auto-compact.
528→    fn context_window(&self) -> u32 {
529→        200_000
530→    }
531→
532→    /// Whether this provider supports vision (image inputs).
533→    /// When true, tool results containing images will be sent as multimodal
534→    /// content blocks instead of stripping the image data.
535→    fn supports_vision(&self) -> bool {
536→        false
537→    }
538→
539→    /// Configured tool mode for this provider, if any.
540→    ///
541→    /// Returns `None` when the provider has no explicit tool mode override
542→    /// (the caller should fall back to `Auto` behavior based on `supports_tools()`).
543→    fn tool_mode(&self) -> Option<moltis_config::ToolMode> {
544→        None
545→    }
546→
547→    /// Stream a completion, yielding delta/done/error events.
548→    fn stream(
549→        &self,
550→        messages: Vec<ChatMessage>,
551→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>>;
552→
553→    /// Stream a completion with tool support.
554→    ///
555→    /// Like `stream()`, but accepts tool schemas and can emit `ToolCallStart`,
556→    /// `ToolCallArgumentsDelta`, and `ToolCallComplete` events in addition to
557→    /// text deltas.
558→    ///
559→    /// Default implementation falls back to `stream()` (ignoring tools).
560→    /// Providers with native streaming tool support should override this.
561→    fn stream_with_tools(
562→        &self,
563→        messages: Vec<ChatMessage>,
564→        _tools: Vec<serde_json::Value>,
565→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
566→        self.stream(messages)
567→    }
568→
569→    /// Configured reasoning effort for this provider instance, if any.
570→    ///
571→    /// Providers that support extended thinking (Anthropic, OpenAI o-series)
572→    /// use this value when building API requests.
573→    fn reasoning_effort(&self) -> Option<ReasoningEffort> {
574→        None
575→    }
576→
577→    /// Return a new provider with reasoning effort set, if supported.
578→    ///
579→    /// Returns `None` for providers that don't support reasoning effort.
580→    /// Used by sub-agent spawning to apply per-agent reasoning settings
581→    /// without mutating the shared registry provider.
582→    fn with_reasoning_effort(
583→        self: Arc<Self>,
584→        _effort: ReasoningEffort,
585→    ) -> Option<Arc<dyn LlmProvider>> {
586→        None
587→    }
588→
589→    /// Send the cheapest request available that proves the model can answer.
590→    ///
591→    /// The default implementation streams a tiny prompt and returns as soon as
592→    /// the first text delta or terminal event arrives. Providers can override
593→    /// this to use provider-specific low-cost probe requests.
594→    async fn probe(&self) -> anyhow::Result<()> {
595→        let probe = vec![ChatMessage::user("ping")];
596→        let mut stream = self.stream(probe);
597→
598→        let result = tokio::time::timeout(Duration::from_secs(30), async {
599→            while let Some(event) = stream.next().await {
600→                match event {
601→                    StreamEvent::Delta(_) | StreamEvent::Done(_) => return Ok(()),
602→                    StreamEvent::Error(err) => return Err(anyhow::anyhow!(err)),
603→                    _ => continue,
604→                }
605→            }
606→            Err(anyhow::anyhow!("stream ended without producing any output"))
607→        })
608→        .await;
609→
610→        drop(stream);
611→
612→        match result {
613→            Ok(inner) => inner,
614→            Err(_) => Err(anyhow::anyhow!("Connection timed out after 30 seconds")),
615→        }
616→    }
617→
618→    /// Fetch runtime model metadata from the provider API.
619→    ///
620→    /// The default implementation returns a `ModelMetadata` derived from the
621→    /// static `context_window()` value. Providers that support a `/models`
622→    /// endpoint can override this to fetch the actual context length at runtime.
623→    async fn model_metadata(&self) -> anyhow::Result<ModelMetadata> {
624→        Ok(ModelMetadata {
625→            id: self.id().to_string(),
626→            context_length: self.context_window(),
627→        })
628→    }
629→}
630→
631→/// Response from an LLM completion call.
632→#[derive(Debug)]
633→pub struct CompletionResponse {
634→    pub text: Option<String>,
635→    pub tool_calls: Vec<ToolCall>,
636→    pub usage: Usage,
637→}
