641→#[derive(Debug, Clone)]
642→pub struct ToolCall {
643→    pub id: String,
644→    pub name: String,
645→    pub arguments: serde_json::Value,
646→    /// Provider-specific opaque metadata to round-trip (e.g. Gemini `thought_signature`).
647→    /// Only allowlisted keys are extracted; see [`TOOL_CALL_METADATA_KEYS`].
648→    pub metadata: Option<serde_json::Map<String, serde_json::Value>>,
649→}
650→
651→/// Keys extracted from provider tool-call JSON into [`ToolCall::metadata`].
652→pub const TOOL_CALL_METADATA_KEYS: &[&str] = &["thought_signature"];
