 18→pub(crate) fn sanitize_qmd_index_name(root: &FsPath) -> String {
 19→    let mut sanitized = String::new();
 20→    let mut previous_was_separator = false;
 21→    for character in root.to_string_lossy().chars() {
 22→        let normalized = character.to_ascii_lowercase();
 23→        if normalized.is_ascii_alphanumeric() {
 24→            sanitized.push(normalized);
 25→            previous_was_separator = false;
 26→        } else if !previous_was_separator {
 27→            sanitized.push('_');
 28→            previous_was_separator = true;
 29→        }
 30→    }
 31→    let sanitized = sanitized.trim_matches('_').to_string();
 32→    if sanitized.is_empty() {
 33→        "moltis".into()
 34→    } else {
 35→        format!("moltis-{sanitized}")
 36→    }
 37→}
