 39→#[cfg(feature = "qmd")]
 40→pub(crate) fn build_qmd_collections(
 41→    data_dir: &FsPath,
 42→    config: &moltis_config::schema::QmdConfig,
 43→) -> HashMap<String, moltis_qmd::QmdCollection> {
 44→    if config.collections.is_empty() {
 45→        return HashMap::from([
 46→            ("moltis-root-memory".into(), moltis_qmd::QmdCollection {
 47→                path: data_dir.to_path_buf(),
 48→                glob: "MEMORY.md".into(),
 49→            }),
 50→            (
 51→                "moltis-root-memory-lower".into(),
 52→                moltis_qmd::QmdCollection {
 53→                    path: data_dir.to_path_buf(),
 54→                    glob: "memory.md".into(),
 55→                },
 56→            ),
 57→            ("moltis-memory".into(), moltis_qmd::QmdCollection {
 58→                path: data_dir.join("memory"),
 59→                glob: "**/*.md".into(),
 60→            }),
 61→            ("moltis-agents".into(), moltis_qmd::QmdCollection {
 62→                path: data_dir.join("agents"),
 63→                glob: "**/*.md".into(),
 64→            }),
 65→        ]);
 66→    }
 67→
 68→    let mut collections = HashMap::new();
 69→    for (name, collection) in &config.collections {
 70→        let globs = if collection.globs.is_empty() {
 71→            vec!["**/*.md".to_string()]
 72→        } else {
 73→            collection.globs.clone()
 74→        };
 75→
 76→        for (path_index, path) in collection.paths.iter().enumerate() {
 77→            let root = FsPath::new(path);
 78→            let root = if root.is_absolute() {
 79→                root.to_path_buf()
 80→            } else {
 81→                data_dir.join(root)
 82→            };
 83→
 84→            for (glob_index, glob) in globs.iter().enumerate() {
 85→                let key = if collection.paths.len() == 1 && globs.len() == 1 {
 86→                    name.clone()
 87→                } else {
 88→                    format!("{name}-{path_index}-{glob_index}")
 89→                };
 90→                collections.insert(key, moltis_qmd::QmdCollection {
 91→                    path: root.clone(),
 92→                    glob: glob.clone(),
 93→                });
 94→            }
 95→        }
 96→    }
 97→
 98→    collections
 99→}
