110→pub(crate) fn instance_slug(config: &moltis_config::MoltisConfig) -> String {
111→    let mut raw_name = config.identity.name.clone();
112→    if let Some(file_identity) = moltis_config::load_identity_for_agent("main")
113→        && file_identity.name.is_some()
114→    {
115→        raw_name = file_identity.name;
116→    }
117→
118→    let base = raw_name
119→        .unwrap_or_else(|| "moltis".to_string())
120→        .to_lowercase();
121→    let mut out = String::new();
122→    let mut last_dash = false;
123→    for ch in base.chars() {
124→        let mapped = if ch.is_ascii_alphanumeric() {
125→            ch
126→        } else {
127→            '-'
128→        };
