130→            if !last_dash {
131→                out.push(mapped);
132→            }
133→            last_dash = true;
134→        } else {
135→            out.push(mapped);
136→            last_dash = false;
137→        }
138→    }
139→    let out = out.trim_matches('-').to_string();
140→    if out.is_empty() {
141→        "moltis".to_string()
142→    } else {
143→        out
144→    }
