186→// ── Model inventory logging ──────────────────────────────────────────────────
187→
188→pub(crate) fn summarize_model_ids_for_logs(
189→    sorted_model_ids: &[String],
190→    max_items: usize,
191→) -> Vec<String> {
192→    if max_items == 0 {
193→        return Vec::new();
194→    }
195→
196→    if sorted_model_ids.len() <= max_items || max_items < 3 {
197→        return sorted_model_ids.iter().take(max_items).cloned().collect();
198→    }
199→
200→    let head_count = max_items / 2;
201→    let tail_count = max_items - head_count - 1;
202→    let mut sample = Vec::with_capacity(max_items);
203→    sample.extend(sorted_model_ids.iter().take(head_count).cloned());
204→    sample.push("...".to_string());
205→    sample.extend(
206→        sorted_model_ids
207→            .iter()
208→            .skip(sorted_model_ids.len().saturating_sub(tail_count))
209→            .cloned(),
210→    );
211→    sample
212→}
