259→pub(crate) async fn ollama_has_model(base_url: &str, model: &str) -> bool {
260→    let url = format!("{}/api/tags", base_url.trim_end_matches('/'));
261→    let response = match reqwest::Client::new().get(url).send().await {
262→        Ok(resp) => resp,
263→        Err(_) => return false,
264→    };
265→    if !response.status().is_success() {
266→        return false;
267→    }
268→    let value: serde_json::Value = match response.json().await {
269→        Ok(v) => v,
270→        Err(_) => return false,
271→    };
272→    value
273→        .get("models")
274→        .and_then(|m| m.as_array())
275→        .map(|models| {
276→            models.iter().any(|m| {
277→                let name = m.get("name").and_then(|n| n.as_str()).unwrap_or_default();
278→                name == model || name.starts_with(&format!("{model}:"))
279→            })
280→        })
281→        .unwrap_or(false)
282→}
