284→pub(crate) async fn ensure_ollama_model(base_url: &str, model: &str) {
285→    if ollama_has_model(base_url, model).await {
286→        return;
287→    }
288→
289→    warn!(
290→        model = %model,
291→        base_url = %base_url,
292→        "memory: missing Ollama embedding model, attempting auto-pull"
293→    );
294→
295→    let url = format!("{}/api/pull", base_url.trim_end_matches('/'));
296→    let pull = reqwest::Client::new()
297→        .post(url)
298→        .json(&serde_json::json!({ "name": model, "stream": false }))
299→        .send()
300→        .await;
301→
302→    match pull {
303→        Ok(resp) if resp.status().is_success() => {
304→            info!(model = %model, "memory: Ollama model pull complete");
305→        },
306→        Ok(resp) => {
307→            warn!(
308→                model = %model,
309→                status = %resp.status(),
310→                "memory: Ollama model pull failed"
311→            );
312→        },
313→        Err(e) => {
314→            warn!(model = %model, error = %e, "memory: Ollama model pull request failed");
315→        },
316→    }
317→}
