361→// ── Memory / process diagnostics ─────────────────────────────────────────────
362→
363→pub(crate) fn process_rss_bytes() -> u64 {
364→    let mut sys = sysinfo::System::new();
365→    let Some(pid) = sysinfo::get_current_pid().ok() else {
366→        return 0;
367→    };
368→    sys.refresh_memory();
369→    sys.refresh_processes_specifics(
370→        sysinfo::ProcessesToUpdate::Some(&[pid]),
371→        false,
372→        sysinfo::ProcessRefreshKind::nothing().with_memory(),
373→    );
374→    sys.process(pid).map(|p| p.memory()).unwrap_or(0)
375→}
