377→pub(crate) struct StartupMemProbe {
378→    enabled: bool,
379→    last_rss_bytes: u64,
380→}
381→
382→impl StartupMemProbe {
383→    pub(crate) fn new() -> Self {
384→        let enabled = env_flag_enabled("MOLTIS_STARTUP_MEM_TRACE");
385→        let last_rss_bytes = if enabled {
386→            process_rss_bytes()
387→        } else {
388→            0
389→        };
390→        Self {
391→            enabled,
392→            last_rss_bytes,
393→        }
394→    }
395→
396→    pub(crate) fn checkpoint(&mut self, stage: &str) {
397→        if !self.enabled {
398→            return;
399→        }
400→        let rss_bytes = process_rss_bytes();
401→        let delta_bytes = rss_bytes as i128 - self.last_rss_bytes as i128;
402→        self.last_rss_bytes = rss_bytes;
403→
404→        info!(
405→            stage,
406→            rss_bytes,
407→            delta_bytes = delta_bytes as i64,
408→            "startup memory checkpoint"
409→        );
410→    }
411→}
