457→pub(crate) fn log_directory_write_probe(dir: &FsPath) {
458→    let nanos = std::time::SystemTime::now()
459→        .duration_since(std::time::UNIX_EPOCH)
460→        .map(|d| d.as_nanos())
461→        .unwrap_or(0);
462→    let probe_path = dir.join(format!(
463→        ".moltis-write-check-{}-{nanos}.tmp",
464→        std::process::id()
465→    ));
466→
467→    match OpenOptions::new()
468→        .create_new(true)
469→        .write(true)
470→        .open(&probe_path)
471→    {
472→        Ok(mut file) => {
473→            if let Err(error) = file.write_all(b"probe") {
474→                warn!(
475→                    path = %probe_path.display(),
476→                    error = %error,
477→                    "startup write probe could not write to config directory"
478→                );
479→            } else {
480→                info!(
481→                    path = %probe_path.display(),
482→                    "startup write probe succeeded for config directory"
483→                );
484→            }
485→            if let Err(error) = std::fs::remove_file(&probe_path) {
486→                warn!(
487→                    path = %probe_path.display(),
488→                    error = %error,
489→                    "failed to clean up startup write probe file"
490→                );
491→            }
492→        },
493→        Err(error) => {
494→            warn!(
495→                path = %probe_path.display(),
496→                error = %error,
497→                "startup write probe failed for config directory"
498→            );
499→        },
500→    }
501→}
