 23→/// Load and parse the config file with env substitution and includes.
 24→pub fn load_config_value(path: &Path) -> crate::Result<serde_json::Value> {
 25→    let raw = std::fs::read_to_string(path).map_err(|source| {
 26→        crate::Error::external(format!("failed to read {}", path.display()), source)
 27→    })?;
 28→    let raw = substitute_env(&raw);
 29→    parse_config_value(&raw, path)
 30→}
