106→/// Find the first config file in standard locations.
107→///
108→/// When a config dir override is set, only that directory is searched —
109→/// project-local and user-global paths are skipped for isolation.
110→pub fn find_config_file() -> Option<PathBuf> {
111→    if let Some(dir) = config_dir_override() {
112→        for name in CONFIG_FILENAMES {
113→            let p = dir.join(name);
114→            if p.exists() {
115→                return Some(p);
116→            }
117→        }
118→        // Override is set — don't fall through to other locations.
119→        return None;
120→    }
121→
122→    // Project-local
123→    for name in CONFIG_FILENAMES {
124→        let p = PathBuf::from(name);
125→        if p.exists() {
126→            return Some(p);
127→        }
128→    }
129→
130→    // User-global: ~/.config/moltis/
131→    if let Some(dir) = home_dir().map(|h| h.join(".config").join("moltis")) {
132→        for name in CONFIG_FILENAMES {
133→            let p = dir.join(name);
134→            if p.exists() {
135→                return Some(p);
136→            }
137→        }
138→    }
139→
140→    None
141→}
