143→pub fn find_or_default_config_path() -> PathBuf {
144→    if let Some(path) = find_config_file() {
145→        return path;
146→    }
147→    config_dir()
148→        .unwrap_or_else(|| PathBuf::from("."))
149→        .join("moltis.toml")
150→}
