186→/// Write raw TOML to the config file, preserving comments.
187→///
188→/// Validates the input by parsing it first. Acquires the config save lock
189→/// so concurrent callers cannot race.  Returns the path written to.
190→pub fn save_raw_config(toml_str: &str) -> crate::Result<PathBuf> {
191→    let _: MoltisConfig = toml::from_str(toml_str)
192→        .map_err(|source| crate::Error::external(format!("invalid config: {source}"), source))?;
193→    let mut guard = CONFIG_SAVE_LOCK.lock().unwrap_or_else(|e| e.into_inner());
194→    let path = find_or_default_config_path();
195→    guard.target_path = Some(path.clone());
196→    if let Some(parent) = path.parent() {
197→        std::fs::create_dir_all(parent)?;
198→    }
199→    std::fs::write(&path, toml_str)?;
200→    debug!(path = %path.display(), "saved raw config");
201→    Ok(path)
202→}
