    set_data_dir(dir.path().to_path_buf());

    let user = UserProfile {
        name: Some("Bob".to_string()),
        timezone: Some(crate::schema::Timezone::from(chrono_tz::US::Eastern)),
        location: Some(crate::schema::GeoLocation {
