    assert!((loc.latitude - 48.8566).abs() < 1e-6);
    assert!((loc.longitude - 2.3522).abs() < 1e-6);
    assert_eq!(loc.place.as_deref(), Some("Paris, France"));

    clear_data_dir();
}

